using sv_3763c6c1c7ab4fa88c9371c9c30323a3.Models;

namespace sv_3763c6c1c7ab4fa88c9371c9c30323a3.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 25),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino.", 20),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 40),
            new(4, "Risotto alla Milanese", "Saffron-infused Arborio rice cooked to creamy perfection.", 35),
        },
        [2] = new List<Recipe>
        {
            new(5, "Tacos al Pastor", "Marinated pork tacos with pineapple and cilantro.", 45),
            new(6, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(7, "Churros", "Fried dough sticks coated in cinnamon sugar with chocolate sauce.", 30),
            new(8, "Enchiladas Verdes", "Corn tortillas filled with chicken and topped with green salsa.", 50),
        },
        [3] = new List<Recipe>
        {
            new(9, "Pad Thai", "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.", 30),
            new(10, "Green Curry", "Coconut milk curry with Thai basil, bamboo shoots, and chicken.", 35),
            new(11, "Tom Yum Soup", "Spicy and sour soup with lemongrass, galangal, and prawns.", 25),
            new(12, "Mango Sticky Rice", "Sweet glutinous rice with fresh mango and coconut cream.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _error;
    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();
            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _loadCts?.Cancel();
        _loadCts?.Dispose();
        _loadCts = new CancellationTokenSource();
        var cts = _loadCts;

        _error = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);
            _recipes = result;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Request was superseded or component disposed; do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private Task Retry() => LoadRecipesAsync();

    public void Dispose()
    {
        _loadCts?.Cancel();
        _loadCts?.Dispose();
    }
}

